{"command": "cd /app/data/auto-opt/utils/llvm-152948 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp 1268 1268

/// Fold (x == C) | ((x & ~M) == C + 1) into (x - C) <u (M + 2)
/// where M+1 is a power of 2.
/// Example: (x == 127) | ((x & -32) == 128) --> (x - 127) <u 33
/// This covers the range [C, C + M + 1].
static Value *foldOrOfEqAndMaskedEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                    InstCombiner::BuilderTy &Builder) {
  // Require OR operation and equality predicates
  if (Cmp0->getPredicate() != ICmpInst::ICMP_EQ ||
      Cmp1->getPredicate() != ICmpInst::ICMP_EQ)
    return nullptr;

  Value *X, *AndOp;
  const APInt *C0, *C1, *Mask;

  // Match: (X == C0) | ((X & Mask) == C1)
  if (!match(Cmp0->getOperand(1), m_APInt(C0)))
    return nullptr;
  X = Cmp0->getOperand(0);

  // Check if Cmp1 is (X & Mask) == C1
  if (!match(Cmp1, m_c_ICmp(ICmpInst::ICMP_EQ,
                            m_And(m_Specific(X), m_APInt(Mask)),
                            m_APInt(C1))))
    return nullptr;

  // Check both comparisons have single use (or at least one does)
  if (!Cmp0->hasOneUse() && !Cmp1->hasOneUse())
    return nullptr;

  // Mask must be negated power of 2 (like -32 = ~31)
  if (!Mask->isNegatedPowerOf2())
    return nullptr;

  // C1 must be C0 + 1 (i.e., C1 is the start of the next aligned block)
  if (*C1 != *C0 + 1)
    return nullptr;

  // M = ~Mask (e.g., 31 from -32)
  APInt M = ~*Mask;
  // M + 1 should be a power of 2
  if (!M.isMask())
    return nullptr;

  // M + 2 is the range size
  APInt RangeSize = M + 2;

  // Result: (X - C0) <u RangeSize
  Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), *C0));
  return Builder.CreateICmpULT(Sub, ConstantInt::get(X->getType(), RangeSize));
}

