{"command": "cd /app/data/auto-opt/utils/llvm-152948 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp 1268 1324
/// Fold (x == C) | ((x & ~M) == C + 1) into (x - C) <u (M + 2)
/// Fold (x != C) & ((x & ~M) != C + 1) into (x - (C + M + 1)) <u (-M - 1)
/// where M+1 is a power of 2.
/// Example: (x == 127) | ((x & -32) == 128) --> (x - 127) <u 33
/// Example: (x != 127) & ((x & -32) != 128) --> (x - 160) <u -33
/// This covers the range [C, C + M + 1] for OR, and its complement for AND.
static Value *foldEqAndMaskedEqLogic(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                     bool IsAnd,
                                     InstCombiner::BuilderTy &Builder) {
  // Determine the expected predicate based on IsAnd
  ICmpInst::Predicate ExpectedPred = IsAnd ? ICmpInst::ICMP_NE : ICmpInst::ICMP_EQ;

  if (Cmp0->getPredicate() != ExpectedPred ||
      Cmp1->getPredicate() != ExpectedPred)
    return nullptr;

  Value *X;
  const APInt *C0, *C1, *Mask;

  // Match: (X OP C0) LOGIC ((X & Mask) OP C1)
  if (!match(Cmp0->getOperand(1), m_APInt(C0)))
    return nullptr;
  X = Cmp0->getOperand(0);

  // Check if Cmp1 is (X & Mask) OP C1
  Value *AndVal;
  if (!match(Cmp1, m_c_ICmp(ExpectedPred,
                            m_And(m_Specific(X), m_APInt(Mask)),
                            m_APInt(C1))))
    return nullptr;
  AndVal = Cmp1->getOperand(0);

  // Check that the comparisons have single use
  if (!Cmp0->hasOneUse() || !Cmp1->hasOneUse())
    return nullptr;
  // Check that the AND operand doesn't have other uses
  if (isa<Instruction>(AndVal) && !AndVal->hasOneUse())
    return nullptr;

  // Mask must be negated power of 2 (like -32 = ~31)
  if (!Mask->isNegatedPowerOf2())
    return nullptr;

  // C1 must be C0 + 1 (i.e., C1 is the start of the next aligned block)
  if (*C1 != *C0 + 1)
    return nullptr;

  // M = ~Mask (e.g., 31 from -32)
  APInt M = ~*Mask;
  // M + 1 should be a power of 2
  if (!M.isMask())
    return nullptr;

  if (IsAnd) {
    // (x != C) & ((x & ~M) != C + 1) --> (x - (C + M + 1)) <u (-M - 1)
    // -M - 1 = ~(M + 1) + 1 = -M - 1
    // For M = 31: -31 - 1 = -32, but expected is -33
    // Actually: -M - 1 where M = 31 gives -32, but we want -33
    // Let me recalculate: the complement of [C, C+M+1] is x < C or x > C+M+1
    // In unsigned: (x - (C + M + 1)) <u (-M - 1)
    // For C=127, M=31: (x - 159) <u -32
    // Hmm, that doesn't match the expected (x - 160) <u -33
    // Let me reconsider...
    // Actually the expected is: (x - 160) <u -33
    // 160 = 127 + 32 + 1 = C + (M + 1) = C + M + 1
    // -33 = -32 - 1 = -(M + 1) - 1
    // Wait, that's not right either. Let me check the math again.
    // The range [127, 159] has size 33 (159 - 127 + 1 = 33)
    // Its complement is x < 127 or x > 159, i.e., x <= 126 or x >= 160
    // We want: (x - 160) <u -33
    // -33 in 32-bit unsigned is 2^32 - 33 = 4294967263
    // For x = 160: (160 - 160) = 0 <u 4294967263 -> true (correct, x >= 160)
    // For x = 127: (127 - 160) = -33 = 4294967263 <u 4294967263 -> false (correct)
    // For x = 126: (126 - 160) = -34 = 4294967262 <u 4294967263 -> true (correct, x < 127)
    // So the formula is: (x - (C + M + 2)) <u (~M - 1)
    // Wait, C + M + 2 = 127 + 31 + 2 = 160. Yes!
    // And ~M - 1 = ~31 - 1 = 0xFFFFFFDF - 1 = 0xFFFFFFDE = -34? No...
    // Let me recalculate: ~M = ~31 = 0xFFFFFFE0 = -32
    // -32 - 1 = -33. Yes!
    // So the formula is: (x - (C + M + 2)) <u (~M - 1)
    // But ~M - 1 = -(M + 1) - 1 = -(M + 2)
    // Hmm, that's -33 for M = 31.
    // And C + M + 2 = 127 + 31 + 2 = 160. Yes!
    APInt SubConst = *C0 + M + 2;
    APInt CmpConst = APInt::getSignedMinValue(M->getBitWidth()) + (M + 1);
    // Actually, ~M - 1 = -M - 1 for two's complement
    // For M = 31: ~31 - 1 = 0xFFFFFFE0 - 1 = 0xFFFFFFDF = -33. Yes!
    CmpConst = (~M) - 1;
    Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), SubConst));
    return Builder.CreateICmpULT(Sub, ConstantInt::get(X->getType(), CmpConst));
  } else {
    // OR case: (x == C) | ((x & ~M) == C + 1) --> (x - C) <u (M + 2)
    APInt RangeSize = M + 2;
    Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), *C0));
    return Builder.CreateICmpULT(Sub, ConstantInt::get(X->getType(), RangeSize));
  }
}

CODEEOF
"}

